<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\SchoolClass;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class SchoolClassController extends Controller { public function index(){return view('admin.classes.index',['items'=>SchoolClass::orderBy('name')->paginate(20)]);} public function create(){return view('admin.classes.form',['item'=>new SchoolClass]);} public function store(Request $r){SchoolClass::create($this->data($r));return redirect()->route('admin.classes.index')->with('success','Kelas ditambahkan.');} public function edit(SchoolClass $class){return view('admin.classes.form',['item'=>$class]);} public function update(Request $r,SchoolClass $class){$class->update($this->data($r,$class));return redirect()->route('admin.classes.index')->with('success','Kelas diperbarui.');} public function destroy(SchoolClass $class){$class->delete();return back()->with('success','Kelas dihapus.');} private function data(Request $r,?SchoolClass $m=null){return $r->validate(['code'=>['required','max:10',Rule::unique('school_classes','code')->ignore($m?->id)],'name'=>'required|max:50','grade'=>'required|in:X,XI,XII','major'=>'nullable|max:50','academic_year'=>'required|max:20','is_active'=>'nullable|boolean']);} }
